const alert = $input.item.json;
const body = alert.body || alert;
const alertData = body.alertData || body.alert || body;
const ticketId = body.ticket_id || alert.ticket_id;

const severityLevel = parseInt(alertData.severity) || 0;
let priority = alertData.priority || 1;

return {
  json: {
    ticket_id: ticketId,
    alertData: {
      ...alertData,
      severity: severityLevel,
      priority: priority
    }
  }
};

const data = $input.item.json;
let analysis = { 
  threat_intent: 'No AI response', 
  cve_list: [], 
  cve_analysis: 'N/A', 
  remediation_options: [], 
  recommended_action: 'None', 
  confidence_score: 0, 
  inconclusive: true 
};

try {
  if (data.choices && data.choices[0]?.message?.content) {
    const text = data.choices[0].message.content;
    const match = text.match(/\{[\s\S]*\}/);
    if (match) analysis = JSON.parse(match[0]);
  }
} catch (e) {
  analysis.threat_intent = 'Error parsing response: ' + e.message;
}

return { json: analysis };

const ana = $input.item.json;
const alertData = $('Parse Alert').item.json.alertData;

let html = `<h2>Deep Threat Analysis Report</h2>\n<h3>Intent: ${ana.threat_intent}</h3>\n<hr>\n<h3>Vulnerability Intelligence</h3>\n<p><strong>CVEs:</strong> ${ana.cve_list.join(', ') || 'None identified'}</p>\n<p>${ana.cve_analysis}</p>\n<hr>\n<h3>Suggested Remediation</h3>\n<ul>`;

ana.remediation_options.forEach(r => {
  html += `<li><strong>${r.action}:</strong> ${r.description} (Confidence: ${(r.confidence * 100).toFixed(0)}%)</li>`;
});

html += `</ul>\n<p><strong>Recommended Next Step:</strong> ${ana.recommended_action}</p>\n<hr>\n<p><strong>AI Confidence:</strong> ${(ana.confidence_score * 100).toFixed(0)}%</p>`;

return { json: { body: html, inconclusive: ana.inconclusive, confidence: ana.confidence_score, cve_list: ana.cve_list } };
